css:
/* Định dạng bảng khi in */
.print-format .table-bordered,
.print-format .table-bordered th,
.print-format .table-bordered td {
    border: 1px solid #000 !important;
}

/* Định dạng chung cho vùng in */
.print-format {
    /* margin-top/left/right đã được quản lý bởi @page margin ở trên, 
       nhưng bạn vẫn có thể giữ padding hoặc margin nội bộ nếu cần */
    orientation: landscape;
    page-size: A4;
    margin-top: 5mm;
    margin-left: 5mm;
    margin-right: 5mm;
}

